    @abstractmethod
    def optimize(self) -> 'Query':
        pass

class Select(Query):
    def __init__(self, columns: List[str], table: str, condition: str = None):
        self.columns = columns
        self.table = table
        self.condition = condition

    def optimize(self) -> 'Query':
        # Check for subqueries in the condition
